You can copy and paste the code below into a file named `house.html` and open it with any modern web browser. This uses **Three.js**, a powerful 3D library.

### Instructions:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, or Safari.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Map for Three.js -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 7); // Start view position

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS (Allow mouse interaction)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(5, 10, 7);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 1024;
        dirLight.shadow.mapSize.height = 1024;
        scene.add(dirLight);

        // 4. CREATE THE HOUSE

        const group = new THREE.Group();

        // --- Materials ---
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xf4a460 }); // Sand/Tan
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Dark Brown
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x2e8b57 }); // Lawn Green

        // --- Floor/Lawn ---
        const groundGeo = new THREE.PlaneGeometry(50, 50);
        const ground = new THREE.Mesh(groundGeo, floorMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- Main Walls ---
        const bodyHeight = 2;
        const bodyWidth = 4;
        const depth = 4;

        const wallGeo = new THREE.BoxGeometry(bodyWidth, bodyHeight, depth);
        const houseBody = new THREE.Mesh(wallGeo, wallMaterial);
        houseBody.position.y = bodyHeight / 2; // Lift off ground
        houseBody.castShadow = true;
        houseBody.receiveShadow = true;
        group.add(houseBody);

        // --- The Roof (Pyramid style) ---
        // We scale a cone to make a pointy roof
        const roofScaleY = 1.5; // Make it taller than walls
        const roofGeo = new THREE.ConeGeometry(Math.sqrt( (bodyWidth/2)**2 + (depth/2)**2 ), bodyHeight * roofScaleY, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = bodyHeight + (bodyHeight * roofScaleY) / 2;
        roof.rotation.y = Math.PI / 4; // Rotate 45deg so square cone fits rectangle
        roof.castShadow = true;
        group.add(roof);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1.2, 2, 0.2);
        const door = new THREE.Mesh(doorGeo, new THREE.MeshStandardMaterial({ color: 0x4a3c31 }));
        door.position.set(0, 1, depth / 2 + 0.1); // Center x, height middle, front wall slightly inside
        group.add(door);

        // Front wall cutout (simulated by adding geometry in front, we don't carve holes in solids easily without UV mapping complexity, 
        // but visually placing the door works fine).

        // --- Windows ---
        function createWindow(xPos, yPos, zDepth) {
            const winGeo = new THREE.PlaneGeometry(1.5, 1.5);
            const win = new THREE.Mesh(winGeo, glassMaterial);
            win.position.set(xPos, yPos, zDepth);
            win.castShadow = true;
            return win;
        }

        // Two windows on front
        group.add(createWindow(-1.2, 1.5, depth/2 + 0.1));
        group.add(createWindow(1.2, 1.5, depth/2 + 0.1));
        // One window on side
        group.add(createWindow(0, 1.5, depth/2 + 0.1)); 

        // --- Chimney ---
        const chimneyGeo = new THREE.BoxGeometry(0.6, 1.5, 0.6);
        const chimney = new THREE.Mesh(chimneyGeo, roofMaterial);
        chimney.position.set(1.8, bodyHeight + 2, 0);
        chimney.castShadow = true;
        group.add(chimney);


        scene.add(group);

        // 5. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }
        animate();

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    </script>
</body>
</html>
